import React, { useMemo, useState } from 'react';
import { Button, Input, Modal, NumberInput, dispatchAppToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { masterService } from '../../../services/master/masterService';
import type {
  AllocationTemplateDto,
  AllocationTemplateLineDto,
  CreateAllocationTemplateDto,
  UpdateAllocationTemplateDto,
} from '../../../services/master/models';
import { normalizeCode } from '../../../utils/codeField';
import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
import { useCatalogListSelection } from '../../../hooks/useCatalogListSelection';
import {
  CatalogCompanyTh,
  CatalogCompanyTd,
  CatalogCompanyField,
  CatalogListShell,
  useCatalogListPaging,
  useCatalogTableBusy,
  SharedCatalogFormActions,
  useSharedCatalog,
  sharedCatalogFormProps,
  isSharedCatalogReadOnly,
  CatalogListGrid,
  CatalogListMasterToolbarSection,
  CatalogListMasterListFooter,
  CatalogFormHistorySlot,
} from '../../../components/catalog';
import type { CatalogBatchDeleteMode } from '../../../components/catalog';
import styles from '../../../styles/erpPage.module.css';

const TEST_ID = 'dm-phan-bo';
const CATALOG_KIND = 'allocation-templates';

const MONTH_KEYS = [
  'monthFactor1', 'monthFactor2', 'monthFactor3', 'monthFactor4',
  'monthFactor5', 'monthFactor6', 'monthFactor7', 'monthFactor8',
  'monthFactor9', 'monthFactor10', 'monthFactor11', 'monthFactor12',
] as const;

type MonthKey = typeof MONTH_KEYS[number];

type FormErrors = Partial<Record<'code' | 'name' | 'accountCode', string>>;

const blankLine = (): AllocationTemplateLineDto => ({
  accountCode: '',
  percentage: 0,
  monthFactor1: 0,
  monthFactor2: 0,
  monthFactor3: 0,
  monthFactor4: 0,
  monthFactor5: 0,
  monthFactor6: 0,
  monthFactor7: 0,
  monthFactor8: 0,
  monthFactor9: 0,
  monthFactor10: 0,
  monthFactor11: 0,
  monthFactor12: 0,
});

interface FlatRow {
  template: AllocationTemplateDto;
  line: AllocationTemplateLineDto;
  lineIndex: number;
  key: string;
  id: string;
  code: string;
  name: string;
  isActive?: boolean;
  isReadOnly?: boolean;
  scope?: string;
}

const PhanBoPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [items, setItems] = useState<AllocationTemplateDto[]>([]);
  const sessionCompanyName = useMemo(() => items[0]?.companyName, [items]);
  const [loading, setLoading] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<AllocationTemplateDto | null>(null);
  const [form, setForm] = useState<Partial<AllocationTemplateDto>>({ method: 'Percentage', isActive: true, lines: [blankLine()] });
  const [errors, setErrors] = useState<FormErrors>({});
  const [saving, setSaving] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [viewOnlyShared, setViewOnlyShared] = useState(false);

  const { page, setPage, pageSize, setPageSize, resetPage } = useCatalogListPaging();
  const { showTableLoading, pulseSearch } = useCatalogTableBusy(loading);

  const flatRows = useMemo<FlatRow[]>(() => items.flatMap(t =>
    (t.lines?.length ? t.lines : [blankLine()]).map((line, lineIndex) => ({
      template: t,
      line,
      lineIndex,
      key: `${t.id}-${lineIndex}`,
      id: t.id,
      code: t.code,
      name: t.name,
      isActive: t.isActive,
      isReadOnly: t.isReadOnly,
      scope: t.scope,
    })),
  ), [items]);

  const totalCount = flatRows.length;
  const pagedFlatRows = useMemo(() => {
    const start = (page - 1) * pageSize;
    return flatRows.slice(start, start + pageSize);
  }, [flatRows, page, pageSize]);

  const selectableOnPage = useMemo(
    () => pagedFlatRows.filter(r => r.lineIndex === 0),
    [pagedFlatRows],
  );

  const selection = useCatalogListSelection({
    rows: pagedFlatRows,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.key,
    isRowSelectable: r => r.lineIndex === 0,
  });

  const refresh = () => {
    selection.clearSelection();
    setReloadKey(k => k + 1);
  };
  const shared = useSharedCatalog(CATALOG_KIND, refresh);
  const sharedForm = sharedCatalogFormProps(CATALOG_KIND, shared);

  const handleSearch = () => {
    pulseSearch(() => {
      setSearch(searchDraft.trim());
      resetPage();
      selection.clearSelection();
    });
  };

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      masterService.getAllocationTemplates({ search: search || undefined })
        .then(data => { if (!cancelled) setItems(data); })
        .catch(err => {
          if (!cancelled) dispatchAppToast(dispatch, { message: err?.message ?? 'Lỗi tải mẫu phân bổ', type: 'error' });
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [search, reloadKey, dispatch]);

  const clearFieldError = (key: keyof FormErrors) => {
    setErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const validate = (): FormErrors => {
    const next: FormErrors = {};
    if (!form.code?.trim()) next.code = 'Nhập mã mẫu phân bổ';
    if (!form.name?.trim()) next.name = 'Nhập tên mẫu phân bổ';
    if (!form.accountCode?.trim()) next.accountCode = 'Nhập TK nguồn phân bổ';
    return next;
  };

  const openAdd = () => {
    setViewOnlyShared(false);
    setEditing(null);
    setForm({ method: 'Percentage', isActive: true, lines: [blankLine()] });
    setErrors({});
    setModalOpen(true);
  };

  const openEdit = (row: FlatRow | AllocationTemplateDto) => {
    const template = 'template' in row ? row.template : row;
    setViewOnlyShared(isSharedCatalogReadOnly(template));
    setEditing(template);
    setForm({
      ...template,
      lines: template.lines?.length ? template.lines.map(l => ({ ...blankLine(), ...l })) : [blankLine()],
    });
    setErrors({});
    setModalOpen(true);
  };

  const updateLine = (idx: number, patch: Partial<AllocationTemplateLineDto>) => {
    setForm(f => ({
      ...f,
      lines: (f.lines ?? []).map((line, i) => i === idx ? { ...line, ...patch } : line),
    }));
  };

  const addLine = () => setForm(f => ({ ...f, lines: [...(f.lines ?? []), blankLine()] }));

  const removeLine = (idx: number) => {
    setForm(f => {
      const lines = [...(f.lines ?? [])];
      if (lines.length <= 1) return f;
      lines.splice(idx, 1);
      return { ...f, lines };
    });
  };

  const handleSave = async () => {
    const nextErrors = validate();
    if (Object.keys(nextErrors).length > 0) {
      setErrors(nextErrors);
      scrollToFirstFieldError(TEST_ID);
      return;
    }
    const lines = (form.lines ?? []).filter(l => l.accountCode.trim());
    if (lines.length === 0) {
      dispatchAppToast(dispatch, { message: 'Thêm ít nhất một dòng TK nhận', type: 'error' });
      return;
    }
    setSaving(true);
    try {
      if (editing) {
        const dto: UpdateAllocationTemplateDto = {
          name: form.name!.trim(),
          accountCode: form.accountCode!.trim(),
          method: form.method ?? 'Percentage',
          isActive: form.isActive ?? true,
          lines,
        };
        await masterService.updateAllocationTemplate(editing.id, dto);
      } else {
        const dto: CreateAllocationTemplateDto = {
          code: form.code!.trim(),
          name: form.name!.trim(),
          accountCode: form.accountCode!.trim(),
          method: form.method ?? 'Percentage',
          lines,
        };
        await masterService.createAllocationTemplate(dto);
      }
      dispatchAppToast(dispatch, { message: editing ? 'Cập nhật mẫu phân bổ thành công' : 'Tạo mẫu phân bổ thành công', type: 'success' });
      setModalOpen(false);
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, { message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' });
    } finally {
      setSaving(false);
    }
  };

  const resolveTemplateIds = (): string[] => {
    if (selection.selectionMode === 'all') {
      return [...new Set(
        flatRows
          .filter(r => r.lineIndex === 0 && !isSharedCatalogReadOnly(r.template))
          .map(r => r.template.id),
      )];
    }
    const ids = [...selection.selectedIds]
      .map(key => flatRows.find(r => r.key === key)?.template.id)
      .filter((id): id is string => !!id);
    return [...new Set(ids)];
  };

  const handleBatchDelete = async (mode: CatalogBatchDeleteMode) => {
    const ids = resolveTemplateIds();
    if (ids.length === 0) throw new Error('Không có bản ghi hợp lệ để xóa');
    if (mode === 'soft') {
      await Promise.all(ids.map(id => {
        const row = items.find(r => r.id === id)!;
        return masterService.updateAllocationTemplate(id, {
          name: row.name,
          accountCode: row.accountCode,
          method: row.method,
          isActive: false,
          lines: row.lines,
        });
      }));
      dispatchAppToast(dispatch, { message: `Đã ngưng ${ids.length} mẫu phân bổ`, type: 'success' });
    } else {
      await Promise.all(ids.map(id => masterService.deleteAllocationTemplate(id)));
      dispatchAppToast(dispatch, { message: `Đã xóa ${ids.length} mẫu phân bổ`, type: 'success' });
    }
    refresh();
  };

  const filterBar = (
    <>
      <div className={styles.field} data-testid={`${TEST_ID}-field-search`}>
        <Input
          placeholder="Tìm mã, tên, TK nguồn..."
          value={searchDraft}
          onChange={e => setSearchDraft(e.target.value)}
          onKeyDown={e => { if (e.key === 'Enter') handleSearch(); }}
        />
      </div>
      <ListSearchRefreshButtons testIdPrefix={TEST_ID} onSearch={handleSearch} onRefresh={refresh} />
    </>
  );

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}><i className="fas fa-share-alt" /> Danh mục phân bổ chi phí</h1>
        </div>
      </div>

      <CatalogListMasterToolbarSection
        testIdPrefix={TEST_ID}
        catalogKind={CATALOG_KIND}
        shared={shared}
        selection={selection}
        totalCount={totalCount}
        selectableOnPage={selectableOnPage}
        onAdd={openAdd}
        onEdit={openEdit}
        onRefresh={refresh}
        onBatchDelete={handleBatchDelete}
      />

      <CatalogListShell
        testIdPrefix={TEST_ID}
        title="Danh sách mẫu phân bổ"
        showTableLoading={showTableLoading}
        filters={filterBar}
        footer={
          <CatalogListMasterListFooter
            testIdPrefix={TEST_ID}
            catalogKind={CATALOG_KIND}
            shared={shared}
            page={page}
            totalCount={totalCount}
            pageSize={pageSize}
            onPageChange={p => { setPage(p); selection.clearSelection(); }}
            onPageSizeChange={setPageSize}
          />
        }
      >
        {pagedFlatRows.length === 0 ? (
          <div className={styles.empty}>
            <i className="fas fa-inbox" />
            <p>{search.trim() ? 'Không tìm thấy mẫu phù hợp' : 'Không có dữ liệu'}</p>
          </div>
        ) : (
          <div className={styles.tableWrapper} style={{ overflowX: 'auto' }}>
            <CatalogListGrid
              testIdPrefix={TEST_ID}
              rows={pagedFlatRows}
              page={page}
              pageSize={pageSize}
              selection={selection}
              getRowId={r => r.key}
              isRowSelectable={r => r.lineIndex === 0}
              headerCells={(
                <>
                  <th>Mã</th>
                  <th>Tên</th>
                  <th>TK nguồn</th>
                  <th>TK nhận</th>
                  <th className={styles.colRight}>% mặc định</th>
                  {MONTH_KEYS.map((_, i) => <th key={i} className={styles.colRight}>T{i + 1}</th>)}
                  <CatalogCompanyTh />
                </>
              )}
              renderRow={r => (
                <>
                  <td><code>{r.template.code}</code></td>
                  <td>{r.template.name}</td>
                  <td><code>{r.template.accountCode}</code></td>
                  <td><code>{r.line.accountCode || '—'}</code></td>
                  <td className={styles.colRight}>{r.line.percentage || 0}</td>
                  {MONTH_KEYS.map(k => (
                    <td key={k} className={styles.colRight}>{Number(r.line[k] ?? 0).toFixed(2)}</td>
                  ))}
                  <CatalogCompanyTd label={r.template.companyName} />
                </>
              )}
            />
          </div>
        )}
      </CatalogListShell>

      <Modal
        isOpen={modalOpen}
        onClose={() => setModalOpen(false)}
        title={viewOnlyShared ? 'Xem mẫu phân bổ dùng chung' : editing ? 'Sửa mẫu phân bổ' : 'Thêm mẫu phân bổ'}
      >
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form`}>
          <div className={styles.formGrid}>
            <div className={styles.masterCodeNameRow}>
              <div className={styles.field} data-testid={`${TEST_ID}-field-code`}>
                <label className={styles.label}>Mã *</label>
                <Input
                  value={form.code ?? ''}
                  disabled={!!editing}
                  error={errors.code}
                  className={styles.codeInput}
                  onChange={e => {
                    clearFieldError('code');
                    setForm(f => ({ ...f, code: normalizeCode(e.target.value) }));
                  }}
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-name`}>
                <label className={styles.label}>Tên *</label>
                <Input
                  value={form.name ?? ''}
                  disabled={viewOnlyShared}
                  error={errors.name}
                  onChange={e => {
                    clearFieldError('name');
                    setForm(f => ({ ...f, name: e.target.value }));
                  }}
                />
              </div>
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-accountCode`}>
              <label className={styles.label}>TK nguồn phân bổ *</label>
              <Input
                value={form.accountCode ?? ''}
                disabled={viewOnlyShared}
                error={errors.accountCode}
                placeholder="627..."
                onChange={e => {
                  clearFieldError('accountCode');
                  setForm(f => ({ ...f, accountCode: e.target.value }));
                }}
              />
            </div>
          </div>

          <h3 className={styles.sectionTitle}>Dòng phân bổ (TK nhận + hệ số tháng)</h3>
          {(form.lines ?? []).map((line, idx) => (
            <div key={idx} className={styles.formGrid} style={{ marginBottom: 12, paddingBottom: 12, borderBottom: '1px solid var(--border-subtle)' }}>
              <div className={styles.field}>
                <label className={styles.label}>TK nhận *</label>
                <Input
                  value={line.accountCode}
                  disabled={viewOnlyShared}
                  onChange={e => updateLine(idx, { accountCode: e.target.value })}
                  placeholder="641..."
                />
              </div>
              <div className={styles.field}>
                <label className={styles.label}>% mặc định</label>
                <NumberInput
                  value={line.percentage}
                  disabled={viewOnlyShared}
                  onChange={v => updateLine(idx, { percentage: v })}
                />
              </div>
              <div style={{ gridColumn: '1 / -1', display: 'grid', gridTemplateColumns: 'repeat(6, 1fr)', gap: 8 }}>
                {MONTH_KEYS.map((k, mi) => (
                  <div key={k} className={styles.field}>
                    <label className={styles.label}>T{mi + 1}</label>
                    <NumberInput
                      value={Number(line[k] ?? 0)}
                      disabled={viewOnlyShared}
                      onChange={v => updateLine(idx, { [k]: v } as Partial<AllocationTemplateLineDto>)}
                    />
                  </div>
                ))}
              </div>
              {!viewOnlyShared && (form.lines?.length ?? 0) > 1 && (
                <Button variant="secondary" onClick={() => removeLine(idx)}>Xóa dòng</Button>
              )}
            </div>
          ))}
          {!viewOnlyShared && <Button variant="secondary" onClick={addLine}>+ Thêm dòng</Button>}

          <CatalogCompanyField testIdPrefix={TEST_ID} companyName={editing?.companyName ?? sessionCompanyName} />
          <SharedCatalogFormActions
            testIdPrefix={TEST_ID}
            row={editing}
            currentValues={{
              name: form.name,
              accountCode: form.accountCode,
            }}
            {...sharedForm}
          />
          <div className={styles.modalActions}>
            <CatalogFormHistorySlot
              testIdPrefix={TEST_ID}
              catalogKind={CATALOG_KIND}
              editing={editing ? { id: editing.id, code: editing.code } : null}
            />
            <Button variant="secondary" onClick={() => setModalOpen(false)}>Hủy</Button>
            <Button
              variant="primary"
              onClick={handleSave}
              disabled={saving || viewOnlyShared}
              data-testid={`${TEST_ID}-save-btn`}
            >
              {saving ? 'Đang lưu...' : 'Lưu'}
            </Button>
          </div>
        </div>
      </Modal>
    </div>
  );
};

export default PhanBoPage;
